const therapistResponses = {
  anger: [
    "I can hear how intense that anger feels. Let’s pause together for a moment — what triggered it?",
    "Feeling angry doesn’t make you a bad person. What’s been building up inside?",
    "Anger often protects deeper emotions. Would you like to explore what’s underneath it?"
  ],

  anxiety: [
    "That sounds overwhelming. Let’s slow this down together. What’s causing the stress?",
    "Anxiety can make everything feel urgent. You’re not alone here."
  ],

  sadness: [
    "I’m really glad you told me this. Feeling lonely can be heavy to carry alone.",
    "Your feelings matter. What’s been weighing on your heart lately?"
  ],

  happiness: [
    "That’s really nice to hear 😊 What’s been helping you feel this way?",
    "I’m glad something positive is happening for you."
  ],

  neutral: [
    "I’m here with you. Take your time — what’s been on your mind?",
    "Would you like to tell me a little more about what you’re experiencing?"
  ]
};

export default therapistResponses;
